import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{ setStats(r.data.data); setLoading(false); }).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'100vh' }}>
      <div style={{ width:36, height:36, border:'3px solid #c9a84c', borderTopColor:'transparent', borderRadius:'50%', animation:'spin 1s linear infinite' }} />
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,    icon:'📚', color:'#3b82f6',  sub:'Library' },
    { label:'Active Members', value:stats?.totalMembers||0,  icon:'👥', color:'#10b981',  sub:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0, icon:'📤', color:'#c9a84c',  sub:'Active' },
    { label:'Overdue',        value:stats?.overdueBorrows||0,icon:'⚠️', color:'#ef4444',  sub:'Urgent' },
  ];

  return (
    <div className="page-enter" style={{ padding:'32px 36px', maxWidth:1200 }}>

      {/* Header */}
      <div style={{ marginBottom:32, display:'flex', alignItems:'flex-end', justifyContent:'space-between' }}>
        <div>
          <p style={{ fontSize:13, color:'rgba(255,255,255,0.3)', letterSpacing:'1px', textTransform:'uppercase', marginBottom:6 }}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:34, fontWeight:700, color:'#fff', lineHeight:1.1 }}>
            Good day, {user?.name?.split(' ')[0]} 👋
          </h1>
        </div>
        <div style={{ textAlign:'right' }}>
          <div style={{ fontSize:12, color:'rgba(255,255,255,0.3)', marginBottom:4 }}>Logged in as</div>
          <div style={{ fontSize:14, fontWeight:600, color:'#c9a84c' }}>{user?.role === 'librarian' ? 'Head Librarian' : user?.role === 'library_assistant' ? 'Library Assistant' : user?.role}</div>
        </div>
      </div>

      {/* Pending Alert */}
      {isStaff && stats && stats.pendingMembers > 0 && (
        <div onClick={()=>navigate('/members?status=pending')} style={{ background:'rgba(245,158,11,0.1)', border:'1px solid rgba(245,158,11,0.3)', borderRadius:14, padding:'16px 20px', marginBottom:24, display:'flex', alignItems:'center', gap:14, cursor:'pointer', transition:'all .2s' }}
          onMouseEnter={e=>(e.currentTarget as any).style.background='rgba(245,158,11,0.15)'}
          onMouseLeave={e=>(e.currentTarget as any).style.background='rgba(245,158,11,0.1)'}>
          <div style={{ width:40, height:40, background:'rgba(245,158,11,0.2)', borderRadius:10, display:'flex', alignItems:'center', justifyContent:'center', fontSize:20, flexShrink:0 }}>⏳</div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:15, fontWeight:700, color:'#fbbf24' }}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{ fontSize:13, color:'rgba(251,191,36,0.6)', marginTop:2 }}>Click to review and approve members</div>
          </div>
          <span style={{ color:'rgba(251,191,36,0.6)', fontSize:20 }}>→</span>
        </div>
      )}

      {/* Pending Requests Alert */}
      {isStaff && stats && stats.pendingRequests > 0 && (
        <div onClick={()=>navigate('/requests')} style={{ background:'rgba(59,130,246,0.1)', border:'1px solid rgba(59,130,246,0.25)', borderRadius:14, padding:'16px 20px', marginBottom:24, display:'flex', alignItems:'center', gap:14, cursor:'pointer', transition:'all .2s' }}
          onMouseEnter={e=>(e.currentTarget as any).style.background='rgba(59,130,246,0.15)'}
          onMouseLeave={e=>(e.currentTarget as any).style.background='rgba(59,130,246,0.1)'}>
          <div style={{ width:40, height:40, background:'rgba(59,130,246,0.2)', borderRadius:10, display:'flex', alignItems:'center', justifyContent:'center', fontSize:20, flexShrink:0 }}>🔔</div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:15, fontWeight:700, color:'#93c5fd' }}>{stats.pendingRequests} borrow request(s) pending review</div>
            <div style={{ fontSize:13, color:'rgba(147,197,253,0.6)', marginTop:2 }}>Click to review and approve requests</div>
          </div>
          <span style={{ color:'rgba(147,197,253,0.6)', fontSize:20 }}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* Stat Cards */}
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16, marginBottom:28 }}>
            {cards.map(c=>(
              <div key={c.label} style={{ background:'#16162a', border:'1px solid rgba(255,255,255,0.07)', borderRadius:18, padding:'22px 22px 18px', transition:'all .2s', cursor:'default' }}
                onMouseEnter={e=>{ (e.currentTarget as any).style.borderColor='rgba(201,168,76,0.25)'; (e.currentTarget as any).style.transform='translateY(-3px)'; (e.currentTarget as any).style.boxShadow='0 12px 36px rgba(0,0,0,0.3)'; }}
                onMouseLeave={e=>{ (e.currentTarget as any).style.borderColor='rgba(255,255,255,0.07)'; (e.currentTarget as any).style.transform='none'; (e.currentTarget as any).style.boxShadow='none'; }}>
                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:18 }}>
                  <div style={{ width:44, height:44, borderRadius:12, background:c.color+'1a', display:'flex', alignItems:'center', justifyContent:'center', fontSize:20 }}>{c.icon}</div>
                  <span style={{ fontSize:11, fontWeight:700, padding:'4px 12px', borderRadius:99, background:c.color+'1a', color:c.color, letterSpacing:'.5px' }}>{c.sub}</span>
                </div>
                <div style={{ fontFamily:"'Playfair Display',serif", fontSize:42, fontWeight:700, color:'#fff', lineHeight:1, marginBottom:6 }}>{c.value}</div>
                <div style={{ fontSize:13, color:'rgba(255,255,255,0.4)', fontWeight:500 }}>{c.label}</div>
                <div style={{ marginTop:14, height:3, background:'rgba(255,255,255,0.06)', borderRadius:99, overflow:'hidden' }}>
                  <div style={{ height:'100%', width:`${Math.min(100, (c.value/Math.max(stats.totalBooks||1,1))*100)}%`, background:c.color, borderRadius:99, transition:'width 1s ease' }} />
                </div>
              </div>
            ))}
          </div>

          {/* Bottom Grid */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:20 }}>
            {/* Recent Borrows */}
            <div style={{ background:'#16162a', border:'1px solid rgba(255,255,255,0.07)', borderRadius:18, padding:24 }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:20 }}>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:18, fontWeight:700, color:'#fff' }}>Recent Borrows</h3>
                <span style={{ fontSize:11, color:'rgba(255,255,255,0.3)', background:'rgba(255,255,255,0.05)', padding:'4px 12px', borderRadius:99 }}>Latest 5</span>
              </div>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
                <div key={b.id} style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 14px', background:'rgba(255,255,255,0.03)', borderRadius:12, marginBottom:8, border:'1px solid rgba(255,255,255,0.04)' }}>
                  <div style={{ width:38, height:38, background:'rgba(201,168,76,0.12)', borderRadius:10, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, fontSize:17 }}>📗</div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:14, fontWeight:600, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.title}</div>
                    <div style={{ fontSize:12, color:'rgba(255,255,255,0.35)', marginTop:2 }}>{b.member_name} · <span style={{ textTransform:'capitalize' }}>{b.account_type}</span></div>
                  </div>
                  <span style={{ fontSize:11, fontWeight:700, padding:'4px 10px', borderRadius:99, background:b.status==='returned'?'rgba(16,185,129,0.15)':b.status==='overdue'?'rgba(239,68,68,0.15)':'rgba(245,158,11,0.15)', color:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24', flexShrink:0, textTransform:'capitalize' }}>{b.status}</span>
                </div>
              )) : <p style={{ color:'rgba(255,255,255,0.25)', fontSize:14, textAlign:'center', padding:'32px 0' }}>No borrows yet</p>}
            </div>

            {/* Popular Books */}
            <div style={{ background:'#16162a', border:'1px solid rgba(255,255,255,0.07)', borderRadius:18, padding:24 }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:20 }}>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:18, fontWeight:700, color:'#fff' }}>Popular Books</h3>
                <span style={{ fontSize:11, color:'rgba(255,255,255,0.3)', background:'rgba(255,255,255,0.05)', padding:'4px 12px', borderRadius:99 }}>Top 5</span>
              </div>
              {stats.popularBooks.length ? stats.popularBooks.map((b:any, i:number)=>(
                <div key={b.title} style={{ display:'flex', alignItems:'center', gap:14, marginBottom:14, padding:'10px 14px', background:'rgba(255,255,255,0.02)', borderRadius:11, border:'1px solid rgba(255,255,255,0.04)' }}>
                  <div style={{ width:30, height:30, borderRadius:8, background:i===0?'linear-gradient(135deg,#c9a84c,#b8962f)':i===1?'rgba(255,255,255,0.08)':i===2?'rgba(201,128,76,0.2)':'rgba(255,255,255,0.05)', color:i===0?'#1a1a2e':'rgba(255,255,255,0.5)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:13, fontWeight:700, flexShrink:0, boxShadow:i===0?'0 3px 10px rgba(201,168,76,0.4)':'none' }}>{i+1}</div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:14, fontWeight:600, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.title}</div>
                    <div style={{ fontSize:12, color:'rgba(255,255,255,0.35)', marginTop:2 }}>{b.author}</div>
                  </div>
                  <div style={{ fontSize:14, fontWeight:700, color:'#c9a84c', flexShrink:0 }}>{b.borrow_count}×</div>
                </div>
              )) : <p style={{ color:'rgba(255,255,255,0.25)', fontSize:14, textAlign:'center', padding:'32px 0' }}>No data yet</p>}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
